def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        if bins[i] <= 0:
            priorities[i] = np.inf
            continue
        space_left = bins[i] - item
        if space_left < 0:
            priorities[i] = np.inf
        elif space_left == 0:
            priorities[i] = 0
        else:
            ratio = item / bins[i]
            cum_priority = 0
            for j in range(1, 5):
                if ratio ** j < 1:
                    cum_priority += (1 / (j)) * (ratio ** j)
                else:
                    cum_priority += (j) * np.log(ratio + 1)
            if space_left < item / 2:
                cum_priority *= 1.5
            priorities[i] = cum_priority
    max_priority = np.max(priorities[np.isfinite(priorities)]) if np.any(np.isfinite(priorities)) else 1
    priorities[np.isinf(priorities)] = max_priority * 10
    return priorities
